import { __ } from '@wordpress/i18n';
import apiFetch from '@wordpress/api-fetch';

interface ProductItem {
    id: number;
    [ key: string ]: any;
}

interface DuplicateActionContext {
    fetchProducts: () => void;
    fetchStatusCounts: () => void;
}

/**
 * Create a duplicate product action object.
 *
 * @param context Object with fetchProducts and fetchStatusCounts callbacks.
 */
export function createDuplicateAction( context: DuplicateActionContext ) {
    return {
        id: 'duplicate',
        label: () => __( 'Duplicate', 'dokan' ),
        callback: async ( items: ProductItem[] ) => {
            const item = items[ 0 ];
            if ( ! item ) {
                return;
            }
            await apiFetch( {
                path: `/dokan/v2/products/${ item.id }/duplicate`,
                method: 'POST',
            } );
            context.fetchProducts();
            context.fetchStatusCounts();
        },
    };
}
